// UTFPR Aulas — Select student course and preserve auth token

const authPayload = $items('UTFPR Auth')[0]?.json || {};
const dadosPayload = $input.first().json || {};

const token = String(authPayload.token || '').trim();
if (!token) {
  return [{
    json: {
      ok: false,
      error: 'auth_failed',
      detail: String(authPayload.message || authPayload.error || 'Token ausente no auth').trim()
    }
  }];
}

const cursosRoot = Array.isArray(dadosPayload?.cursos) ? dadosPayload.cursos : [];
const cursosAluno = Array.isArray(dadosPayload?.aluno?.cursos) ? dadosPayload.aluno.cursos : [];
const cursos = cursosRoot.length > 0 ? cursosRoot : cursosAluno;
const preferredCod = String($env.UTFPR_COD_ALUNO || '').trim();

let selected = null;
if (preferredCod) {
  selected = cursos.find(course => String(course?.alCuIdVc || '') === preferredCod) || null;
}
if (!selected) {
  selected = cursos[0] || null;
}

if (!selected || !selected.alCuIdVc) {
  return [{
    json: {
      ok: false,
      error: 'course_not_found',
      detail: 'Nao foi possivel determinar codAluno em /dados para consultar horario',
      token
    }
  }];
}

return [{
  json: {
    ok: true,
    token,
    codAluno: String(selected.alCuIdVc),
    cursoNome: String(selected.cursNomeVc || selected.curso || ''),
    nomeAluno: String(dadosPayload.pessNomeVc || dadosPayload.nome || ''),
    ra: String(dadosPayload.login || dadosPayload.ra || ''),
    preferredCod
  }
}];

// UTFPR Aulas — Parse auth/dados/horario/boletim payloads into reusable data

const TZ = 'America/Sao_Paulo';
const DAY_LABELS = {
  1: 'DOM',
  2: 'SEG',
  3: 'TER',
  4: 'QUA',
  5: 'QUI',
  6: 'SEX',
  7: 'SAB'
};

const TURN_ORDER = { M: 0, T: 1, N: 2 };
const SLOT_TIMES = {
  M: {
    1: ['07:30', '08:20'],
    2: ['08:20', '09:10'],
    3: ['09:10', '10:00'],
    4: ['10:20', '11:10'],
    5: ['11:10', '12:00'],
    6: ['12:00', '12:50']
  },
  T: {
    1: ['13:00', '13:50'],
    2: ['13:50', '14:40'],
    3: ['14:40', '15:30'],
    4: ['15:50', '16:40'],
    5: ['16:40', '17:30'],
    6: ['17:30', '18:20']
  },
  N: {
    1: ['18:40', '19:30'],
    2: ['19:30', '20:20'],
    3: ['20:20', '21:10'],
    4: ['21:20', '22:10'],
    5: ['22:10', '23:00']
  }
};

function safeNumber(v, fallback = 0) {
  const n = Number(v);
  return Number.isFinite(n) ? n : fallback;
}

function toMinutes(hhmm) {
  const [hh, mm] = String(hhmm || '00:00').split(':').map(Number);
  if (!Number.isFinite(hh) || !Number.isFinite(mm)) return 0;
  return hh * 60 + mm;
}

function countSlotsInBlock(block) {
  const start = Number(block?.slotStart);
  const end = Number(block?.slotEnd);
  if (Number.isFinite(start) && Number.isFinite(end) && end >= start) {
    return end - start + 1;
  }
  return 1;
}

function shiftHHmm(hhmm, deltaMinutes) {
  const total = ((toMinutes(hhmm) + deltaMinutes) % 1440 + 1440) % 1440;
  const hh = String(Math.floor(total / 60)).padStart(2, '0');
  const mm = String(total % 60).padStart(2, '0');
  return `${hh}:${mm}`;
}

function nowInfoInTz() {
  const now = new Date();
  const weekdayShort = now.toLocaleDateString('en-US', {
    timeZone: TZ,
    weekday: 'short'
  });

  const weekdayMap = {
    Sun: 1,
    Mon: 2,
    Tue: 3,
    Wed: 4,
    Thu: 5,
    Fri: 6,
    Sat: 7
  };

  const todayDayNumber = weekdayMap[weekdayShort] || 1;

  const timeParts = new Intl.DateTimeFormat('pt-BR', {
    timeZone: TZ,
    hour: '2-digit',
    minute: '2-digit'
  }).formatToParts(now);

  const hh = Number(timeParts.find(part => part.type === 'hour')?.value || 0);
  const mm = Number(timeParts.find(part => part.type === 'minute')?.value || 0);
  return {
    todayDayNumber,
    nowMinutes: hh * 60 + mm
  };
}

function parseHoraDescr(code) {
  const raw = String(code || '').trim().toUpperCase();
  const match = raw.match(/^(\d)([MTN])(\d)$/);
  if (!match) return null;

  const dia = Number(match[1]);
  const turno = match[2];
  const slot = Number(match[3]);

  if (!DAY_LABELS[dia]) return null;
  if (!SLOT_TIMES[turno] || !SLOT_TIMES[turno][slot]) return null;

  return { dia, turno, slot };
}

function parseHorarioPayload(payload) {
  const rows = Array.isArray(payload) ? payload : [];
  const slots = [];

  rows.forEach(row => {
    const disciplina = String(row?.discNomeVc || '').trim();
    const cod = String(row?.discCodVelhoVc || '').trim();
    const horarios = Array.isArray(row?.horarios) ? row.horarios : [];
    const professores = Array.isArray(row?.professores) ? row.professores : [];
    const professor = String(professores[0]?.pessNomeVc || '').trim();

    horarios.forEach(h => {
      const parsed = parseHoraDescr(h?.horaDescrVc);
      if (!parsed) return;

      const slotWindow = SLOT_TIMES[parsed.turno][parsed.slot];
      const sala = String(h?.ambienteNomeVc || '').trim();

      slots.push({
        dia: parsed.dia,
        dayLabel: DAY_LABELS[parsed.dia],
        turno: parsed.turno,
        slot: parsed.slot,
        inicio: slotWindow[0],
        fim: slotWindow[1],
        disciplina,
        cod,
        sala,
        professor
      });
    });
  });

  slots.sort((a, b) => {
    if (a.dia !== b.dia) return a.dia - b.dia;
    if (a.turno !== b.turno) return TURN_ORDER[a.turno] - TURN_ORDER[b.turno];
    return a.slot - b.slot;
  });

  return slots;
}

function mergeConsecutiveSlots(slots) {
  const merged = [];

  slots.forEach(slot => {
    const prev = merged[merged.length - 1];
    const canMerge =
      prev &&
      prev.dia === slot.dia &&
      prev.turno === slot.turno &&
      prev.disciplina === slot.disciplina &&
      prev.cod === slot.cod &&
      prev.slotEnd + 1 === slot.slot;

    if (!canMerge) {
      merged.push({
        dia: slot.dia,
        dayLabel: slot.dayLabel,
        turno: slot.turno,
        slotStart: slot.slot,
        slotEnd: slot.slot,
        inicio: slot.inicio,
        fim: slot.fim,
        disciplina: slot.disciplina,
        cod: slot.cod,
        salas: slot.sala ? [slot.sala] : [],
        professor: slot.professor
      });
      return;
    }

    prev.slotEnd = slot.slot;
    prev.fim = slot.fim;

    if (slot.sala && !prev.salas.includes(slot.sala)) {
      prev.salas.push(slot.sala);
    }

    if (!prev.professor && slot.professor) {
      prev.professor = slot.professor;
    }
  });

  return merged.map(item => ({
    dia: item.dia,
    dayLabel: item.dayLabel,
    dayOffset: 0,
    turno: item.turno,
    slotStart: item.slotStart,
    slotEnd: item.slotEnd,
    inicio: item.inicio,
    fim: item.fim,
    disciplina: item.disciplina,
    cod: item.cod,
    sala: item.salas.join('/'),
    professor: item.professor || ''
  }));
}

function parseBoletimPayload(payload) {
  const rows = Array.isArray(payload) ? payload : [];
  const map = {};

  rows.forEach(row => {
    const cod = String(row?.discCodVelhoVc || '').trim();
    if (!cod) return;

    const faltas = safeNumber(row?.faltas, 0);
    const aulasDadas = safeNumber(row?.aulasDadas, 0);
    const aulasPrevistas = safeNumber(row?.aulasPrevistas, 0);
    const limiteFaltas = aulasPrevistas > 0 ? Math.floor(aulasPrevistas * 0.25) : null;

    map[cod] = {
      faltas,
      aulasDadas,
      aulasPrevistas,
      limiteFaltas,
      faltasRestantes: Number.isFinite(limiteFaltas) ? limiteFaltas - faltas : null,
      faltaPercent: aulasDadas > 0 ? Number(((100 * faltas) / aulasDadas).toFixed(1)) : null
    };
  });

  return map;
}

function collectRowsFromItems(nodeName) {
  return $items(nodeName).flatMap(item => {
    const json = item?.json;
    if (Array.isArray(json)) return json;
    if (json && typeof json === 'object') return [json];
    return [];
  });
}

const authPayload = $items('UTFPR Auth')[0]?.json || {};
const selectedCourse = $items('Select UTFPR Course')[0]?.json || {};
const horarioPayload = collectRowsFromItems('UTFPR Horario');
const boletimPayload = collectRowsFromItems('UTFPR Boletim');

if (!selectedCourse.ok) {
  const detail = String(selectedCourse.detail || authPayload.message || authPayload.error || '').trim();
  return [{
    json: {
      ok: false,
      error: selectedCourse.error || 'utfpr_data_unavailable',
      detail,
      todayClasses: [],
      todayAbsences: [],
      hint: null
    }
  }];
}

const nowInfo = nowInfoInTz();
const slots = parseHorarioPayload(horarioPayload);
const mergedBlocks = mergeConsecutiveSlots(slots);
const absencesByCode = parseBoletimPayload(boletimPayload);

const blocks = mergedBlocks.map(block => {
  const dayOffset = (block.dia - nowInfo.todayDayNumber + 7) % 7;
  const absence = block.cod ? absencesByCode[block.cod] || null : null;
  return {
    ...block,
    dayOffset,
    absence
  };
});

blocks.sort((a, b) => {
  if (a.dayOffset !== b.dayOffset) return a.dayOffset - b.dayOffset;
  if (a.turno !== b.turno) return TURN_ORDER[a.turno] - TURN_ORDER[b.turno];
  return a.slotStart - b.slotStart;
});

const todayClasses = blocks
  .filter(block => block.dayOffset === 0)
  .sort((a, b) => toMinutes(a.inicio) - toMinutes(b.inicio));

const todayClassSlots = todayClasses.reduce((acc, block) => acc + countSlotsInBlock(block), 0);

const nowOrUpcomingToday = todayClasses
  .filter(block => toMinutes(block.fim) >= nowInfo.nowMinutes)
  .sort((a, b) => toMinutes(a.inicio) - toMinutes(b.inicio));

let hint = null;
const prepMinutes = safeNumber($env.UTFPR_PREP_MINUTES, 45);
const commuteMinutes = safeNumber($env.UTFPR_COMMUTE_MINUTES, 20);

if (nowOrUpcomingToday.length > 0) {
  const first = nowOrUpcomingToday[0];
  hint = {
    when: 'hoje',
    dayLabel: first.dayLabel,
    classStartsAt: first.inicio,
    arrumarAt: shiftHHmm(first.inicio, -prepMinutes),
    sairAt: shiftHHmm(first.inicio, -commuteMinutes),
    prepMinutes,
    commuteMinutes
  };
}

const todayAbsences = [];
const seenTodayDisciplines = new Set();

todayClasses.forEach(block => {
  const disciplineKey = String(block.cod || block.disciplina || '').trim();
  if (!disciplineKey || seenTodayDisciplines.has(disciplineKey)) return;

  seenTodayDisciplines.add(disciplineKey);
  const abs = block.absence || {};

  todayAbsences.push({
    cod: String(block.cod || ''),
    disciplina: String(block.disciplina || ''),
    faltas: safeNumber(abs.faltas, 0),
    aulasDadas: Number.isFinite(Number(abs.aulasDadas)) ? Number(abs.aulasDadas) : null,
    aulasPrevistas: Number.isFinite(Number(abs.aulasPrevistas)) ? Number(abs.aulasPrevistas) : null,
    limiteFaltas: Number.isFinite(Number(abs.limiteFaltas)) ? Number(abs.limiteFaltas) : null,
    faltasRestantes: Number.isFinite(Number(abs.faltasRestantes)) ? Number(abs.faltasRestantes) : null,
    faltaPercent: Number.isFinite(Number(abs.faltaPercent)) ? Number(abs.faltaPercent) : null
  });
});

todayAbsences.sort((a, b) => String(a.disciplina).localeCompare(String(b.disciplina), 'pt-BR'));

const absencesSummary = todayAbsences.reduce(
  (acc, row) => {
    acc.disciplines += 1;
    acc.totalFaltas += safeNumber(row.faltas, 0);
    if (Number.isFinite(row.limiteFaltas)) {
      acc.totalLimiteFaltas += row.limiteFaltas;
    }
    if (Number.isFinite(row.faltasRestantes)) {
      acc.totalRestantes += row.faltasRestantes;
    }
    return acc;
  },
  { disciplines: 0, totalFaltas: 0, totalLimiteFaltas: 0, totalRestantes: 0 }
);

return [{
  json: {
    ok: true,
    source: 'utfpr-aulas',
    generatedAtMs: Date.now(),
    todayDayNumber: nowInfo.todayDayNumber,
    student: {
      nome: String(selectedCourse.nomeAluno || ''),
      ra: String(selectedCourse.ra || ''),
      curso: String(selectedCourse.cursoNome || ''),
      codAluno: String(selectedCourse.codAluno || '')
    },
    totals: {
      slots: slots.length,
      blocks: blocks.length,
      todayBlocks: todayClasses.length,
      todaySlots: todayClassSlots,
      todayDisciplines: seenTodayDisciplines.size,
      today: todayClasses.length,
      next: 0
    },
    hint,
    absencesSummary,
    todayAbsences,
    todayClasses,
    nextClasses: [],
    allBlocks: todayClasses
  }
}];

const data = $input.first().json;
const CLASSROOM_BASE = String($env.CLASSROOM_API_BASE_URL).replace(/\/$/, '');
if (!data.courses || data.courses.length === 0) {
  return [{ json: { courseName: '__none__', noCourses: true, url: `${CLASSROOM_BASE}/courses/0/courseWork` } }];
}
return data.courses.map(c => ({
  json: {
    courseName: c.name,
    noCourses: false,
    url: `${CLASSROOM_BASE}/courses/${c.id}/courseWork`
  }
}));

// Daily Briefing — unified formatting for Calendar + Moodle + Classroom + Aulas

function esc(t) { return String(t).replace(/([_*`\[\]])/g, '\\$1'); }

function plural(value, one, many) {
  return Number(value) === 1 ? one : many;
}

const TZ = 'America/Sao_Paulo';
const nowMs = Date.now();
const in14dMs = nowMs + 14 * 24 * 60 * 60 * 1000;
const in48hMs = nowMs + 48 * 60 * 60 * 1000;

const gcalItems = $items('Google Calendar');
const moodleItem = $items('Moodle API') && $items('Moodle API').length > 0 ? $items('Moodle API')[0].json : {};
const prepItems = $items('Prep Classroom');
const cwItems = $items('Get CourseWork');
const aulasData = $items('Parse Aulas Data') && $items('Parse Aulas Data').length > 0
  ? $items('Parse Aulas Data')[0].json
  : null;

function dayKey(ms) {
  const parts = new Intl.DateTimeFormat('pt-BR', {
    timeZone: TZ,
    year: 'numeric',
    month: '2-digit',
    day: '2-digit'
  }).formatToParts(new Date(ms));

  const year = parts.find(p => p.type === 'year').value;
  const month = parts.find(p => p.type === 'month').value;
  const day = parts.find(p => p.type === 'day').value;
  return `${year}-${month}-${day}`;
}

function formatDay(ms) {
  return new Date(ms)
    .toLocaleDateString('pt-BR', {
      timeZone: TZ,
      weekday: 'short',
      day: '2-digit',
      month: '2-digit'
    })
    .toUpperCase();
}

function formatTime(ms) {
  return new Date(ms).toLocaleTimeString('pt-BR', {
    timeZone: TZ,
    hour: '2-digit',
    minute: '2-digit'
  });
}

function parseCalendarStart(start) {
  if (!start) return null;

  if (start.dateTime) {
    const ms = new Date(start.dateTime).getTime();
    if (!Number.isFinite(ms)) return null;
    return { ms, allDay: false };
  }

  if (start.date) {
    const parts = String(start.date).split('-').map(Number);
    if (parts.length !== 3 || parts.some(Number.isNaN)) return null;

    const [year, month, day] = parts;
    const ms = Date.UTC(year, month - 1, day, 3, 0, 0);
    return { ms, allDay: true };
  }

  return null;
}

function startOfTodayInTzMs() {
  const parts = new Intl.DateTimeFormat('pt-BR', {
    timeZone: TZ,
    year: 'numeric',
    month: '2-digit',
    day: '2-digit'
  }).formatToParts(new Date());

  const year = Number(parts.find(p => p.type === 'year').value);
  const month = Number(parts.find(p => p.type === 'month').value);
  const day = Number(parts.find(p => p.type === 'day').value);

  // 00:00 BRT represented in UTC.
  return Date.UTC(year, month - 1, day, 3, 0, 0);
}

function pseudoMsFromOffset(dayOffset, hhmm) {
  const dayMs = 24 * 60 * 60 * 1000;
  const [hh, mm] = String(hhmm || '00:00').split(':').map(Number);
  const minutes = Number.isFinite(hh) && Number.isFinite(mm) ? hh * 60 + mm : 0;
  return startOfTodayInTzMs() + dayOffset * dayMs + minutes * 60 * 1000;
}

const todayKey = dayKey(nowMs);
const events = [];

function buildEvent(ms, allDay, context, title) {
  const key = dayKey(ms);
  const isToday = key === todayKey;

  const priority = isToday
    ? 'HOJE'
    : ms <= in48hMs
      ? 'URGENTE'
      : 'PROXIMO';

  return {
    ms,
    allDay,
    priority,
    context,
    title,
    day: formatDay(ms),
    time: allDay ? 'O DIA TODO' : formatTime(ms),
    isToday
  };
}

function countSlotsInBlock(block) {
  const start = Number(block?.slotStart);
  const end = Number(block?.slotEnd);
  if (Number.isFinite(start) && Number.isFinite(end) && end >= start) {
    return end - start + 1;
  }
  return 1;
}

function formatAbsenceStatus(absence) {
  const faltas = Number.isFinite(Number(absence?.faltas)) ? Number(absence.faltas) : 0;
  const limite = Number.isFinite(Number(absence?.limiteFaltas)) ? Number(absence.limiteFaltas) : null;
  const restantes = Number.isFinite(Number(absence?.faltasRestantes)) ? Number(absence.faltasRestantes) : null;

  let status = Number.isFinite(limite)
    ? `*${faltas}/${limite}*`
    : `*${faltas}*`;

  if (Number.isFinite(limite) && Number.isFinite(restantes)) {
    status += restantes >= 0
      ? ` | Restam *${restantes}*`
      : ` | Excesso *${Math.abs(restantes)}*`;
  }

  return status;
}

// 1) Google Calendar items (keep all-day only for today to reduce noise in briefing)
gcalItems.forEach(item => {
  const event = item.json || {};
  const parsed = parseCalendarStart(event.start);
  if (!parsed) return;

  const isToday = dayKey(parsed.ms) === todayKey;
  if (parsed.allDay && !isToday) return;

  events.push(buildEvent(parsed.ms, parsed.allDay, 'AGENDA', esc(event.summary || 'Sem titulo')));
});

// 2) Moodle items
if (Array.isArray(moodleItem.events)) {
  moodleItem.events.forEach(event => {
    if (!event || !event.timestart) return;

    const ms = Number(event.timestart) * 1000;
    if (!Number.isFinite(ms) || ms < nowMs - 5 * 60 * 1000) return;

    const course = esc(event.course && event.course.shortname ? event.course.shortname.trim() : 'MOODLE');
    const title = esc(event.name || 'Atividade sem titulo');
    events.push(buildEvent(ms, false, course, title));
  });
}

// 3) Classroom items
for (let i = 0; i < prepItems.length; i++) {
  const prep = prepItems[i].json || {};
  if (prep.noCourses) break;

  const coursework = cwItems[i] ? cwItems[i].json : {};
  const works = Array.isArray(coursework.courseWork) ? coursework.courseWork : [];

  works.forEach(work => {
    if (!work.dueDate) return;

    const year = Number(work.dueDate.year);
    const month = Number(work.dueDate.month);
    const day = Number(work.dueDate.day);
    if (!Number.isFinite(year) || !Number.isFinite(month) || !Number.isFinite(day)) return;

    // 23:59 BRT represented in UTC.
    const dueMs = Date.UTC(year, month - 1, day, 2, 59, 0);
    if (!Number.isFinite(dueMs) || dueMs < nowMs || dueMs > in14dMs) return;

    events.push(buildEvent(dueMs, false, esc(prep.courseName || 'CLASSROOM'), esc(work.title || 'Tarefa sem titulo')));
  });
}

// 4) UTFPR classes (/aulas)
if (aulasData && aulasData.ok) {
  const todayClasses = Array.isArray(aulasData.todayClasses) ? aulasData.todayClasses : [];
  const classBlocks = todayClasses.slice(0, 14);

  classBlocks.forEach(block => {
    const dayOffset = Number(block.dayOffset || 0);
    const start = String(block.inicio || '00:00');
    const ms = pseudoMsFromOffset(dayOffset, start);

    const cod = esc(block.cod || 'DISC');
    const disciplina = esc(block.disciplina || 'Aula');
    const sala = block.sala ? ` (Sala ${esc(block.sala)})` : '';
    const title = `${cod} - ${disciplina}${sala}`;

    events.push(buildEvent(ms, false, 'AULAS', title));
  });
}

events.sort((a, b) => a.ms - b.ms);

const todayItems = events.filter(event => event.isToday);
const nextItems = events.filter(event => !event.isToday);
const urgentCount = events.filter(event => event.ms > nowMs && event.ms <= in48hMs).length;

function renderItems(items) {
  return items
    .map(item => {
      const context = item.context;
      const title = item.title;
      const when = item.allDay
        ? `${item.day} — O DIA TODO`
        : `${item.day} as ${item.time}`;
      return `• *[${item.priority}]* *[${context}]* ${title}\n  Quando: ${when}`;
    })
    .join('\n\n');
}

let message = `*Briefing Integrado - ${formatDay(nowMs)}*\n\n`;

message += '*RESUMO*\n';
message += `• Total: *${events.length}*\n`;
message += `• Hoje: *${todayItems.length}*\n`;
message += `• Urgentes (<48h): *${urgentCount}*\n\n`;

if (aulasData && aulasData.ok) {
  const totals = aulasData.totals || {};
  const todayClasses = Array.isArray(aulasData.todayClasses) ? aulasData.todayClasses : [];
  const absRows = Array.isArray(aulasData.todayAbsences) ? aulasData.todayAbsences : [];

  const aulasBlocos = Number.isFinite(Number(totals.todayBlocks))
    ? Number(totals.todayBlocks)
    : todayClasses.length;
  const aulasSlots = Number.isFinite(Number(totals.todaySlots))
    ? Number(totals.todaySlots)
    : todayClasses.reduce((acc, block) => acc + countSlotsInBlock(block), 0);
  const disciplinasHoje = Number.isFinite(Number(totals.todayDisciplines))
    ? Number(totals.todayDisciplines)
    : new Set(todayClasses.map(block => String(block.cod || block.disciplina || '').trim()).filter(Boolean)).size;

  message += `• Aulas hoje: *${aulasSlots}* ${plural(aulasSlots, 'aula', 'aulas')} em *${aulasBlocos}* ${plural(aulasBlocos, 'bloco', 'blocos')}\n`;
  message += `• Disciplinas: *${disciplinasHoje}*\n`;

  if (aulasData.hint && aulasData.hint.when === 'hoje') {
    message += `• Dica: arrumar *${esc(aulasData.hint.arrumarAt)}* | sair *${esc(aulasData.hint.sairAt)}*\n`;
  }

  if (absRows.length === 0) {
    message += '• Frequencia: sem dados de faltas para hoje\n';
  } else {
    absRows.slice(0, 6).forEach(row => {
      const cod = esc(row.cod || 'DISC');
      const disciplina = esc(row.disciplina || 'Sem nome');
      message += `• [${cod}] ${disciplina}: ${formatAbsenceStatus(row)}\n`;
    });
  }

  message += '\n';
}

message += '*HOJE*\n';
if (todayItems.length === 0) {
  message += 'Nenhum item para hoje.\n';
} else {
  message += `${renderItems(todayItems)}\n`;
}

message += '\n*PROXIMOS DIAS*\n';
if (nextItems.length === 0) {
  message += 'Nenhum item nos proximos dias.';
} else {
  message += renderItems(nextItems);
}

return [{ json: { text: message.trim() } }];
